import {ADD_COMMENT, DELETE_ARTICLE, LOAD_ALL_ARTICLES, START} from '../types'
import {arrToMap} from '../utils'
import {Map, fromJS, Record} from 'immutable'

const ArticleRecord = Record({
    id: null,
    text: null,
    title: null,
    date: null,
    comments: []
})

const ReducerState = Record({
    entities: arrToMap([], ArticleRecord),
    loading: false,
    loaded: false,
    error: null

})

export default function (articles = new ReducerState(), action) {
    const {type, payload, randomId, response} = action

    switch (type) {
        case LOAD_ALL_ARTICLES:
            return articles.set('entities', arrToMap(response, ArticleRecord))

        case DELETE_ARTICLE:
            /*const articlesCopy = {...articles}
            delete articlesCopy[payload.id]
            return articlesCopy*/
            return articles.deleteIn(['entities', payload.id])

        case ADD_COMMENT:
            /*const article = articles[payload.articleId]
            const comments = article.comments || []
            return {
                ...articles,
                [payload.articleId]: {
                    ...article,
                    comments: [...comments, randomId]
                }
            }*/
            return articles.updateIn(
                ['entities', payload.articleId, 'comments'],
                (comments) => {
                    comments.concat(randomId)
                }
            )

        case LOAD_ALL_ARTICLES + START:
            return articles.set('entities', arrToMap(response, ArticleRecord))

        default:
            return articles
    }
}
